// ---- Object (singleton) ----
object Logger {
    var logLevel: String = "INFO"

    fun log(message: String) {
        println("[$logLevel] $message")
    }

    fun setLevel(level: String) {
        logLevel = level
    }
}

// ---- Object expression (anonymous class) ----
interface Greeter {
    fun greet(): String
}

fun createGreeter(name: String): Greeter {
    return object : Greeter {
        override fun greet(): String {
            return "Hello, $name!"
        }
    }
}

// ---- Class with companion object ----
class User(
    val id: Int,
    val name: String
) {
    companion object {
        private var nextId = 0

        fun create(name: String): User {
            return User(++nextId, name)
        }

        fun createMultiple(names: List<String>): List<User> {
            return names.map { create(it) }
        }
    }
}

// ---- Companion object with name ----
class Product(
    val id: Int,
    val name: String
) {
    companion object Factory {
        fun create(name: String): Product {
            return Product(generateId(), name)
        }

        private fun generateId(): Int {
            return (1..1000).random()
        }
    }
}

// ---- Companion object with properties ----
class Config {
    companion object {
        const val APP_NAME = "Kotlin-chan App"
        const val VERSION = "1.0.0"
        private val _settings = mutableMapOf<String, String>()

        fun set(key: String, value: String) {
            _settings[key] = value
        }

        fun get(key: String): String? = _settings[key]
    }
}

fun main() {
    // ---- Using object ----
    Logger.log("Application started")
    Logger.setLevel("DEBUG")
    Logger.log("Debug message")

    // ---- Object expression ----
    val greeter = createGreeter("Kotlin-chan")
    println(greeter.greet())

    val anotherGreeter = createGreeter("Java-chan")
    println(anotherGreeter.greet())

    // ---- Companion object ----
    val user1 = User.create("Alice")
    val user2 = User.create("Bob")
    val users = User.createMultiple(listOf("Charlie", "Dave"))

    println("User1: ${user1.id} - ${user1.name}")
    println("User2: ${user2.id} - ${user2.name}")
    users.forEach { println("User: ${it.id} - ${it.name}") }

    // ---- Companion object with name ----
    val product = Product.Factory.create("Laptop")
    println("Product: ${product.id} - ${product.name}")

    // ---- Companion object with properties ----
    println("App: ${Config.APP_NAME}, Version: ${Config.VERSION}")
    Config.set("theme", "dark")
    println("Theme: ${Config.get("theme")}")
}

