object MathUtils {
    val pi = 3.14159

    fun factorial(n: Int): Long {
        return if (n <= 1) 1 else n * factorial(n - 1)
    }

    fun isEven(n: Int): Boolean = n % 2 == 0
}

class Counter(val value: Int) {
    companion object {
        fun create(start: Int = 0) = Counter(start)
    }
}

fun main() {
    println("PI: ${MathUtils.pi}")
    println("5! = ${MathUtils.factorial(5)}")
    println("Is 4 even? ${MathUtils.isEven(4)}")

    val counter = Counter.create(10)
    println("Counter: ${counter.value}")
    val defaultCounter = Counter.create()
    println("Default counter: ${defaultCounter.value}")
}
